form:Form.form:Scripts:
		var CLASS_TREE;

function RefreshTree()
{          
	CLASS_TREE=clsClientTree("contDATA","SELECT","CLOCK.ico","folder-close.ico","folder.ico","item.ico",true,LoadChilds,null,onClick,1000);
	if (Ctrl("c_rol_etty").GetXValue()!="")
	{
	  //Consulta RAIZ
	  var nSQL = GetProxy().SQLService();
	 	var resultxt=nSQL.Get(Ctrl("main").getResource("Roles"), "<DATA TYPE=\"ROOT\" c_rol_etty=\""+Ctrl("c_rol_etty").GetXValue()+"\" oi_thread=\""+Ctrl("oi_thread").GetXValue()+"\" ETTY=\""+Ctrl("ETTY").GetXValue()+"\" />");

	 	CLASS_TREE.SetXML(null, resultxt);
	} else
	{ 
	 	CLASS_TREE.SetXML(null, "<tree/>");
	}

	Ctrl("SELECT").SetXValue("");
	RefreshButtons();
}

function RefreshButtons()
{          
	CtrlEnabled("ACCEPT", Ctrl("SELECT").GetXValue()!="");


}

function LoadChilds(objTree, objGroup)
{
	nSQL = GetProxy().SQLService();

	var id=objGroup.FullId.split("/");   

	//Genero el Parametro	
	var param=new NomadXML("DATA");      
	param.SetAttr("TYPE", objGroup.Tag.split('|')[0]);
	param.SetAttr("ETTY", Ctrl("ETTY").GetXValue());
	param.SetAttr("oi_thread", Ctrl("oi_thread").GetXValue());
	param.SetAttr("ID", id[id.length-1]);

	//Resultado
	var resultxt=nSQL.Get(Ctrl("main").getResource("Roles"), param.ToString());
  objTree.SetXML(objGroup.FullId, resultxt);
}

function onClick(objTree, objGroup)
{
	var id=objGroup.FullId.split("/");

	switch(objGroup.Tag.split('|')[0])
	{
		case "ROL":
			Ctrl("c_rol").SetXValue(id[id.length-1]);
			Ctrl("c_estructura").SetXValue("");
			Ctrl("oi_entidad").SetXValue("");
			break;

		case "EST":                 
			if (id.length>=2) Ctrl("c_rol").SetXValue(id[id.length-2]);
			             else	Ctrl("c_rol").SetXValue(objGroup.Tag.split('|')[1]);
			Ctrl("c_estructura").SetXValue(id[id.length-1]);
			Ctrl("oi_entidad").SetXValue("");
			break;

		case "ETT":
			if (id.length>=3) Ctrl("c_rol").SetXValue(id[id.length-3]);
			else
			{
				pg=objTree.GetGroup(id[id.length-2]);
				Ctrl("c_rol").SetXValue(pg.Tag.split('|')[1]);
			}
			Ctrl("c_estructura").SetXValue(id[id.length-2]);
			Ctrl("oi_entidad").SetXValue(id[id.length-1]);
			break;

		default:
			Ctrl("c_rol").SetXValue("");
			Ctrl("c_estructura").SetXValue("");
			Ctrl("oi_entidad").SetXValue("");
			break;
	}   
	/*
	alert(
			Ctrl("c_rol").GetXValue()
			+"-"+
			Ctrl("c_estructura").GetXValue()
			+"-"+
			Ctrl("oi_entidad").GetXValue()
	);
	*/

  RefreshButtons();
}

function OnLoad() {

	if (Ctrl("ETTY").GetXValue()=="")
		Ctrl("ETTY").SetXValue(GetProxy().Etty());       

	//Creo el OBJETO TREE
	CLASS_TREE=clsClientTree("contDATA","SELECT","CLOCK.ico","folder-close.ico","folder.ico","item.ico",true,LoadChilds,null,onClick,1000);

	//Actualizo el TREE
	RefreshTree();     
}
